import java.util.HashSet;

public class Hashset {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		HashSet<String> set = new HashSet<String>();
		set.add("Apple");
		set.add("Apple");
		set.add("Orange");
		set.add("Orange");
		set.add("Banana");
		set.add("Banana");
		System.out.println(set);
	}

}
